const secrets = $input.all();
const apiKey = secrets.find(x => x.json.name === 'OPENROUTER_AUTOMATION_API_KEY')?.json.data;
const chatId = secrets.find(x => x.json.name === 'PERSONAL_TELEGRAM_CHAT_ID')?.json.data;
const config = $('Configuration').first().json;

return {
  json: {
    api_key: apiKey,
    chat_id: chatId,
    ...config
  }
};

const htmlText = $input.item.json.content_html || '';
const cleanText = htmlText.replace(/<[^>]*>?/gm, ' ').replace(/\s+/g, ' ').trim();
const modelName = $('Format Config').item.json.model_name;

const prompt = `You are an expert content classifier for social media, specifically Twitter (X). Your context is a Spanish-speaking user base (primarily Mexico), though tweets may occasionally be in English.

Your task is to analyze a single tweet and output a JSON object containing the detected language and a list of applicable categories.

### OUTPUT FORMAT
Return ONLY valid JSON. Do not include markdown formatting.
{
  "language": "String (Spanish, English, or Other)",
  "categories": ["CATEGORY_STRING_1", "CATEGORY_STRING_2"]
}

### LANGUAGE RULES
- Detect the language of the tweet.
- Valid values: "Spanish", "English", "Other".
- If the tweet uses "Spanglish", categorize it as "Spanish".

### CATEGORY DEFINITIONS
Evaluate the tweet against the following categories. A tweet may belong to multiple categories (e.g., a political event could be both POLITICS and NEWS_GENERAL). If it fits none, use NO_CATEGORY.

1. NEWS_GENERAL
   - Reports on current events, crime, accidents, traffic reports, celebrity gossip (weddings, breakups), or viral stories that would appear on a news broadcast.
   - Exclude sports unless it is a major breaking headline.

2. WEATHER
   - Mentions availability of rain, droughts, heatwaves, temperature updates, earthquakes (seismic alerts), or hurricanes.

3. SOCIAL_EVENTS
   - Announcements of public gatherings, concerts, festivals, cinema premieres, exhibitions, or cultural activities.
   - "Things to do" in the city.

4. PROMOTION
   - Advertising, brand promos, sales, discounts, or influencers clearly selling a product.

5. SCAMS_AND_CRYPTO
   - Cryptocurrency discussions, NFTs, "get rich quick" schemes, phishing attempts, or suspicious bot-like links.

6. POLITICS
   - Any discussion regarding government, laws, international relations, or elections.
   - **Context (Mexico):** Mentions of parties (MORENA, PAN, PRI, PRD, MC/Movimiento Ciudadano, PT, PVEM). Mentions of figures (AMLO/López Obrador, Claudia Sheinbaum, Xóchitl Gálvez, Samuel García, Marcelo Ebrard).
   - **Context (USA):** Mentions of Joe Biden, Donald Trump, US borders, migration policies.
   - **Context (General):** Feminism, protests, social justice movements, labor reform.

7. MEMES_AND_HUMOR
   - Tweets intended to be funny, sarcastic, or referencing internet culture.
   - Use of heavy slang, copypastas, or references to viral trends.

8. SPORTS
   - Discussion of soccer (Liga MX, National Team), F1 (Checo Pérez), Baseball, American Football, or olympics.

9. NO_CATEGORY
   - For tweets that are personal thoughts ("I am hungry"), random conversations that lack context to be understood, greetings, complains, or text that does not carry informational value fitting the categories above.

### EXAMPLES

Input: "Se pronostican lluvias fuertes en CDMX para hoy en la tarde, tomen precauciones."
Output: {"language": "Spanish", "categories": ["WEATHER", "NEWS_GENERAL"]}

Input: "Vote for the new law regarding crypto regulation! Check this link [link]"
Output: {"language": "English", "categories": ["SCAMS_AND_CRYPTO", "POLITICS"]}

Input: "El PRI y el PAN anunciaron su coalición para las próximas elecciones."
Output: {"language": "Spanish", "categories": ["POLITICS", "NEWS_GENERAL"]}

Input: "Vendo boletos para el corona capital, info por DM."
Output: {"language": "Spanish", "categories": ["SOCIAL_EVENTS", "PROMOTION"]}

Input: "Checo Pérez acaba de ganar el segundo lugar en el GP!!"
Output: {"language": "Spanish", "categories": ["SPORTS", "NEWS_GENERAL"]}

Input: "Tengo mucha hambre."
Output: {"language": "Spanish", "categories": ["NO_CATEGORY"]}

### INPUT TWEET:
${cleanText}`;

return {
  json: {
    ...$input.item.json,
    clean_text: cleanText,
    request_body: {
      model: modelName,
      messages: [
        { role: "user", content: prompt }
      ]
    }
  }
};

const response = $input.item.json.choices?.[0]?.message?.content || '{}';
const sourceTweetId = $('Prepare Prompt').item.json.tweet_id;
const modelId = $('Get/Register Model ID').item.json.id;

// Clean Markdown Wrappers (```json ... ```)
const regex = /```(?:json)?\s*([\s\S]*?)\s*```/;
const match = response.match(regex);
const jsonStr = match ? match[1] : response;

try {
  const parsed = JSON.parse(jsonStr);

  return {
    json: {
      tweet_id: sourceTweetId,
      model_id: modelId,
      language: parsed.language || 'Unknown',
      categories: JSON.stringify(parsed.categories || []),
      metadata: JSON.stringify({
         attempted_at: new Date().toISOString()
      })
    }
  };
} catch (e) {
  throw new Error(`JSON Parse Failed: ${e.message}. Raw: ${jsonStr.substring(0, 50)}...`);
}
